#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 100005
int T, n;
int* edges[MAXN];
int* visited;
int* mex;
int count;
void dfs(int v, int* perm, int idx) {
    if (idx == n) {
        // calculate MEX for each vertex
        for (int i = 0; i < n; i++) {
            int v = perm[i];
            int mex_v = 0;
            while (visited[mex_v] == 1) mex_v++;
            mex[v] = mex_v;
            visited[mex_v] = 1;
        }
        // count distinct sequences A(P)
        int* seq = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            seq[i] = mex[perm[i]];
        }
        // check if seq is already counted
        int found = 0;
        for (int i = 0; i < count; i++) {
            int* seq_i = (int*) malloc(n * sizeof(int));
            for (int j = 0; j < n; j++) {
                seq_i[j] = mex[perm[j]];
            }
            if (compare(seq, seq_i) == 0) {
                found = 1;
                break;
            }
        }
        if (!found) {
            count++;
        }
        free(seq);
    } else {
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                perm[idx] = i;
                visited[i] = 1;
                dfs(v, perm, idx + 1);
                visited[i] = 0;
            }
        }
    }
}
int compare(int* a, int* b) {
    for (int i = 0; i < n; i++) {
        if (a[i] != b[i]) return 0;
    }
    return 1;
}
int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            edges[i] = (int*) malloc(2 * sizeof(int));
            scanf("%d %d", &edges[i][0], &edges[i][1]);
        }
        visited = (int*) malloc(n * sizeof(int));
        mex = (int*) malloc(n * sizeof(int));
        int* perm = (int*) malloc(n * sizeof(int));
        count = 0;
        dfs(0, perm, 0);
        printf("%d\n", count);
        free(perm);
        free(mex);
        free(visited);
        for (int i = 0; i < n; i++) {
            free(edges[i]);
        }
    }
    return 0;
}

