#include <iostream>
#include <vector>
#include <set>
using namespace std;
#define MOD 1000000007
#define MAXN 100005
int T, n;
vector<int> edges[MAXN];
set<int> visited;
set<int> mex;
int count;
void dfs(int v, vector<int> perm, int idx) {
    if (idx == n) {
        // calculate MEX for each vertex
        for (int i = 0; i < n; i++) {
            int v = perm[i];
            int mex_v = 0;
            while (visited.find(mex_v) != visited.end()) mex_v++;
            mex.insert(mex_v);
            visited.insert(v);
        }
        // count distinct sequences A(P)
        vector<int> seq;
        for (int i = 0; i < n; i++) {
            seq.push_back(*mex.begin());
            mex.erase(mex.begin());
        }
        // check if seq is already counted
        if (count.find(seq) == count.end()) {
            count.insert(seq);
        }
    } else {
        for (int i = 0; i < n; i++) {
            if (visited.find(i) == visited.end()) {
                perm.push_back(i);
                visited.insert(i);
                dfs(v, perm, idx + 1);
                visited.erase(i);
                perm.pop_back();
            }
        }
    }
}
