import java.util.Scanner;
import java.util.Set;
import java.util.HashSet;
public class Main {
    static int T, n;
    static int[][] edges;
    static Set<Integer> visited;
    static Set<Integer> mex;
    static int count;
    public static void dfs(int v, int[] perm, int idx) {
        if (idx == n) {
            // calculate MEX for each vertex
            for (int i = 0; i < n; i++) {
                int v = perm[i];
                int mex_v = 0;
                while (visited.contains(mex_v)) mex_v++;
                mex.add(mex_v);
                visited.add(v);
            }
            // count distinct sequences A(P)
            int[] seq = new int[n];
            for (int i = 0; i < n; i++) {
                seq[i] = mex.iterator().next();
                mex.remove(mex.iterator().next());
            }
            // check if seq is already counted
            if (!count.contains(seq)) {
                count.add(seq);
            }
        } else {
            for (int i = 0; i < n; i++) {
                if (!visited.contains(i)) {
                    perm[idx] = i;
                    visited.add(i);
                    dfs(v, perm, idx + 1);
                    visited.remove(i);
                }
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        T = sc.nextInt();
        while (T-- > 0) {
            n = sc.nextInt();
            edges = new int[n][2];
            for (int i = 0; i < n; i++) {
                int u = sc.nextInt();
                int v = sc.nextInt();
                edges[u][0] = v;
                edges[v][0] = u;
            }
            visited = new HashSet<>();
            mex = new HashSet<>();
            count = 0;
            dfs(0, new int[n], 0);
            System.out.println(count);
        }
    }
}

